import { generateMetadata } from "@/lib/metadata";
import { armadaData } from "@/data/bylian.data";
import { Bus, Users, Shield, Wifi, Coffee, Music, CheckCircle2 } from "lucide-react";
import Image from "next/image";

export const metadata = generateMetadata({
    title: "Varian Armada Bus",
    description: "Kenali fasilitas lengkap armada bus Super Eksekutif, Eksekutif, dan Bisnis AC PT Bylian Trans.",
    path: "/armada",
});

export default function ArmadaPage() {
    return (
        <div className="pt-24 pb-20">
            <div className="container mx-auto px-4 sm:px-6 lg:px-8 max-w-7xl">
                <div className="text-center max-w-3xl mx-auto mb-16">
                    <h1 className="text-4xl md:text-5xl font-black text-slate-800 tracking-tight mb-4">Spesifikasi Armada</h1>
                    <p className="text-lg text-slate-600">
                        Perjalanan aman dan nyaman dengan armada bus terbaru berspesifikasi tinggi, dirancang untuk memanjakan istirahat Anda sepanjang perjalanan.
                    </p>
                </div>

                <div className="space-y-24">
                    {armadaData.map((armada, idx) => (
                        <div key={armada.id} className={`flex flex-col lg:flex-row gap-12 lg:gap-20 items-center ${idx % 2 !== 0 ? 'lg:flex-row-reverse' : ''}`}>

                            {/* Image Section */}
                            <div className="w-full lg:w-1/2 relative">
                                <div className="aspect-[4/3] rounded-3xl overflow-hidden shadow-2xl relative group">
                                    <img src={armada.image} alt={armada.name} className="w-full h-full object-cover group-hover:scale-105 transition duration-700" />

                                    {/* Floating Badge */}
                                    <div className="absolute top-6 right-6 bg-white/90 backdrop-blur px-4 py-2 rounded-full font-black text-primary shadow-lg border border-white/50">
                                        {armada.name}
                                    </div>
                                </div>
                                {/* Decorative blob */}
                                <div className={`absolute -z-10 w-full h-full rounded-3xl bg-slate-100 ${idx % 2 !== 0 ? 'top-6 -left-6' : 'top-6 -right-6'}`} />
                            </div>

                            {/* Content Section */}
                            <div className="w-full lg:w-1/2">
                                <div className="mb-6">
                                    <span className="inline-block px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-bold tracking-wider uppercase mb-4">Kelas {armada.name}</span>
                                    <h2 className="text-3xl lg:text-4xl font-black text-slate-800 mb-4">{armada.name} <span className="text-slate-400 font-light">|</span> {armada.kapasitas} Seat</h2>
                                    <p className="text-slate-600 text-lg leading-relaxed">
                                        {armada.description}
                                    </p>
                                </div>

                                <div className="grid grid-cols-2 gap-4 mb-8">
                                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                        <p className="text-xs text-slate-500 uppercase font-semibold mb-1">Konfigurasi Kursi</p>
                                        <p className="font-bold text-slate-800">{armada.konfigurasi}</p>
                                    </div>
                                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                        <p className="text-xs text-slate-500 uppercase font-semibold mb-1">Kapasitas Maksimal</p>
                                        <p className="font-bold text-slate-800">{armada.kapasitas} Penumpang</p>
                                    </div>
                                </div>

                                <h3 className="font-bold text-lg text-slate-800 mb-4 flex items-center gap-2">
                                    <Shield className="w-5 h-5 text-primary" /> Fasilitas Lengkap
                                </h3>
                                <ul className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                    {armada.fasilitas.map((f, i) => (
                                        <li key={i} className="flex items-start gap-3">
                                            <CheckCircle2 className="w-5 h-5 text-green-500 shrink-0" />
                                            <span className="text-slate-700 font-medium">{f}</span>
                                        </li>
                                    ))}
                                </ul>
                            </div>

                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

"use client";

import { Bus, Clock, MapPin, CheckCircle2 } from "lucide-react";
import { formatIDR } from "@/lib/utils";
import { getWhatsAppCharterUrl } from "@/lib/whatsapp";

interface CharterPackageProps {
    pkg: {
        id: string;
        title: string;
        destination: string;
        duration: string;
        busClass: string;
        capacity: string;
        startPrice: number;
        features: string[];
        image: string;
    }
}

export function CharterPackageCard({ pkg }: CharterPackageProps) {

    const handleBooking = () => {
        window.open(getWhatsAppCharterUrl(`Halo, saya tertarik dengan Paket Charter: ${pkg.title} (${pkg.busClass}). Boleh minta info lebih detail?`), "_blank");
    };

    return (
        <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 group flex flex-col h-full">
            <div className="relative h-48 overflow-hidden bg-slate-200">
                {/* Placeholder image structure */}
                {pkg.image ? (
                    <img src={pkg.image} alt={pkg.title} className="w-full h-full object-cover group-hover:scale-110 transition duration-700" />
                ) : (
                    <div className="w-full h-full bg-slate-200 flex items-center justify-center text-slate-400">
                        <Bus className="w-12 h-12 opacity-50" />
                    </div>
                )}
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur text-primary text-xs font-black px-3 py-1.5 rounded-full shadow-sm">
                    {pkg.busClass}
                </div>
            </div>

            <div className="p-6 flex flex-col flex-1">
                <h3 className="font-bold text-xl text-slate-800 mb-2 leading-tight">{pkg.title}</h3>

                <div className="flex flex-wrap gap-4 mt-2 mb-4">
                    <div className="flex items-center gap-1.5 text-xs text-slate-500 font-medium">
                        <MapPin className="w-3.5 h-3.5" /> {pkg.destination}
                    </div>
                    <div className="flex items-center gap-1.5 text-xs text-slate-500 font-medium">
                        <Clock className="w-3.5 h-3.5" /> {pkg.duration}
                    </div>
                    <div className="flex items-center gap-1.5 text-xs text-slate-500 font-medium">
                        <Bus className="w-3.5 h-3.5" /> {pkg.capacity}
                    </div>
                </div>

                <div className="space-y-2 mb-6 flex-1">
                    {pkg.features.map((feature, i) => (
                        <div key={i} className="flex items-start gap-2 text-sm text-slate-600">
                            <CheckCircle2 className="w-4 h-4 text-green-500 shrink-0 mt-0.5" />
                            <span>{feature}</span>
                        </div>
                    ))}
                </div>

                <div className="pt-4 border-t border-slate-100 flex items-end justify-between mt-auto">
                    <div>
                        <p className="text-[10px] text-slate-500 uppercase font-semibold mb-1">Mulai Dari</p>
                        <p className="text-lg font-black text-primary">{formatIDR(pkg.startPrice)}</p>
                    </div>
                    <button
                        onClick={handleBooking}
                        className="bg-slate-100 hover:bg-primary hover:text-white text-slate-800 px-5 py-2.5 rounded-xl font-bold transition-colors text-sm"
                    >
                        Pesan via WA
                    </button>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { X, ZoomIn } from "lucide-react";

interface GalleryItem {
    id: string;
    url: string;
    category: "EXTERIOR" | "INTERIOR" | "FASILITAS";
    alt: string;
}

export function GalleryGrid({ images }: { images: GalleryItem[] }) {
    const [selectedImage, setSelectedImage] = useState<GalleryItem | null>(null);

    return (
        <>
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                {images.map((item) => (
                    <div
                        key={item.id}
                        className="group relative aspect-square bg-slate-200 rounded-2xl overflow-hidden cursor-pointer shadow-sm hover:shadow-lg transition-all"
                        onClick={() => setSelectedImage(item)}
                    >
                        <img src={item.url} alt={item.alt} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />

                        <div className="absolute inset-0 bg-slate-900/40 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center">
                            <ZoomIn className="w-8 h-8 text-white scale-50 group-hover:scale-100 transition-transform duration-300" />
                        </div>

                        <div className="absolute bottom-3 left-3 bg-white/90 backdrop-blur px-2.5 py-1 rounded-md text-[10px] font-bold text-slate-800">
                            {item.category}
                        </div>
                    </div>
                ))}
            </div>

            {/* Lightbox Modal */}
            {selectedImage && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/95 backdrop-blur-sm p-4">
                    <button
                        onClick={() => setSelectedImage(null)}
                        className="absolute top-6 right-6 p-2 bg-white/10 hover:bg-white/20 text-white rounded-full transition-colors"
                    >
                        <X className="w-6 h-6" />
                    </button>

                    <div className="max-w-5xl w-full max-h-[85vh] relative animate-in fade-in zoom-in-95 duration-200">
                        <img src={selectedImage.url} alt={selectedImage.alt} className="w-full h-full object-contain mx-auto" />
                        <p className="text-white text-center mt-4 tracking-wide font-medium">{selectedImage.alt}</p>
                    </div>
                </div>
            )}
        </>
    );
}
